<?php require_once 'config.php'; require_admin(); require_once 'header.php';
if($_SERVER['REQUEST_METHOD']==='POST'){ if(!empty($_POST['id'])){ $pdo->prepare('UPDATE users SET full_name=?, username=?, email=?, phone=?, role=? WHERE id=?')->execute([$_POST['full_name'],$_POST['username'],$_POST['email'],$_POST['phone'],$_POST['role'],$_POST['id']]); } else { $pdo->prepare('INSERT INTO users (full_name, username, email, phone, password, role) VALUES (?,?,?,?,?,?)')->execute([$_POST['full_name'],$_POST['username'],$_POST['email'],$_POST['phone'],password_hash($_POST['password'],PASSWORD_DEFAULT),$_POST['role']]); } flash('success','User amehifadhiwa.'); header('Location: users.php'); exit; }
if(isset($_GET['delete']) && $_GET['delete'] != $_SESSION['user_id']){ $pdo->prepare('DELETE FROM users WHERE id=?')->execute([$_GET['delete']]); flash('success','User amefutwa.'); header('Location: users.php'); exit; }
$edit=null; if(isset($_GET['edit'])){$s=$pdo->prepare('SELECT * FROM users WHERE id=?');$s->execute([$_GET['edit']]);$edit=$s->fetch();} $rows=$pdo->query('SELECT * FROM users ORDER BY id DESC')->fetchAll();
?>
<h1>User Management</h1><form class="panel grid-form" method="post"><input type="hidden" name="id" value="<?= e($edit['id'] ?? '') ?>"><input name="full_name" placeholder="Full name" value="<?= e($edit['full_name'] ?? '') ?>" required><input name="username" placeholder="Username" value="<?= e($edit['username'] ?? '') ?>" required><input type="email" name="email" placeholder="Email" value="<?= e($edit['email'] ?? '') ?>" required><input name="phone" placeholder="Phone" value="<?= e($edit['phone'] ?? '') ?>"><?php if(!$edit): ?><input type="password" name="password" placeholder="Password" required><?php endif; ?><select name="role"><option <?= (($edit['role'] ?? '')==='Admin')?'selected':'' ?>>Admin</option><option <?= (($edit['role'] ?? '')==='Cashier')?'selected':'' ?>>Cashier</option></select><button>Save User</button></form>
<div class="panel"><table><tr><th>ID</th><th>Name</th><th>Username</th><th>Email</th><th>Phone</th><th>Role</th><th>Action</th></tr><?php foreach($rows as $r): ?><tr><td><?= e($r['id']) ?></td><td><?= e($r['full_name']) ?></td><td><?= e($r['username']) ?></td><td><?= e($r['email']) ?></td><td><?= e($r['phone']) ?></td><td><?= e($r['role']) ?></td><td><a href="?edit=<?= e($r['id']) ?>">Edit</a> <?php if($r['id']!=$_SESSION['user_id']): ?><a class="danger" href="?delete=<?= e($r['id']) ?>" onclick="return confirm('Futa user?')">Delete</a><?php endif; ?></td></tr><?php endforeach; ?></table></div>
<?php require_once 'footer.php'; ?>
